+  if (buf == nullptr) {
+    LOG("Cannot allocate memory for path to %s", rel);
+    return nullptr;
+  }
+  char *end = static_cast<char*>(mempcpy(buf, fname, last_slash - fname + 1));
+  memcpy(end, rel, rel_size);
+  return buf;
+}
